import android.app.Activity
import android.content.Intent
import android.net.Uri
import android.os.Bundle

class MainActivity : Activity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        handleDeepLink(intent)
    }

    private fun handleDeepLink(intent: Intent) {
        val action = intent.action
        val data: Uri? = intent.data

        if (Intent.ACTION_VIEW == action && data != null) {
            when (data.host) {
                "profile" -> {
                    val userId = data.lastPathSegment
                    navigateToProfileActivity(userId)
                }
                "payment" -> {
                    when (data.lastPathSegment) {
                        "confirm" -> navigateToPaymentConfirmationActivity()
                    }
                }
            }
        }
    }

    private fun navigateToProfileActivity(userId: String?) {
        val intent = Intent(this, ProfileActivity::class.java).apply {
            putExtra("userId", userId)
        }
        startActivity(intent)
    }

    private fun navigateToPaymentConfirmationActivity() {
        val intent = Intent(this, PaymentConfirmationActivity::class.java)
        startActivity(intent)
    }
}